import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
  signal,
} from '@angular/core';
import { POPOVER_CONTEXT, type PopoverContext } from './popover.context';

let _popoverIdCounter = 0;

@Component({
  selector: 'n-popover',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents', 'data-slot': 'root' },
  providers: [
    {
      provide: POPOVER_CONTEXT,
      useFactory: (cmp: PopoverComponent) => cmp.context,
      deps: [forwardRef(() => PopoverComponent)],
    },
  ],
})
export class PopoverComponent {
  readonly nOpen = model<boolean>(false);
  readonly nId = input<string>('');
  readonly nPersistent = input<boolean>(false);
  readonly nModal = input<boolean>(false);
  readonly nTrigger = input<'click' | 'hover' | 'focus'>('click');

  readonly nOpenChange = output<boolean>();

  private readonly _staticId = `n-popover-${++_popoverIdCounter}`;
  private readonly _triggerEl = signal<HTMLElement | null>(null);
  private readonly _panelEl = signal<HTMLElement | null>(null);
  private _closeTimer?: ReturnType<typeof setTimeout>;

  readonly rootId = computed(() => this.nId() || this._staticId);

  readonly context: PopoverContext = {
    open: this.nOpen,
    persistent: this.nPersistent,
    modal: this.nModal,
    triggerMode: this.nTrigger,
    triggerEl: this._triggerEl.asReadonly(),
    panelEl: this._panelEl.asReadonly(),
    get contentId() {
      return '';
    },
    get triggerId() {
      return '';
    },
    setTriggerEl: (el) => this._triggerEl.set(el),
    setPanelEl: (el) => this._panelEl.set(el),
    toggle: () => this._setOpen(!this.nOpen()),
    openPopover: () => {
      clearTimeout(this._closeTimer);
      this._setOpen(true);
    },
    close: (focusTrigger = true) => {
      clearTimeout(this._closeTimer);
      this._setOpen(false);
      if (focusTrigger) this._triggerEl()?.focus();
    },
    scheduleClose: (focusTrigger = false, delay = 150) => {
      clearTimeout(this._closeTimer);
      this._closeTimer = setTimeout(() => {
        this._setOpen(false);
        if (focusTrigger) this._triggerEl()?.focus();
      }, delay);
    },
    cancelScheduledClose: () => {
      clearTimeout(this._closeTimer);
    },
  };

  constructor() {
    Object.defineProperty(this.context, 'contentId', {
      get: () => `${this.rootId()}-content`,
    });
    Object.defineProperty(this.context, 'triggerId', {
      get: () => `${this.rootId()}-trigger`,
    });
  }

  private _setOpen(value: boolean): void {
    if (this.nOpen() === value) return;
    this.nOpen.set(value);
    this.nOpenChange.emit(value);
  }
}

import { Directive, ElementRef, OnDestroy, inject } from '@angular/core';
import { POPOVER_CONTEXT } from './popover.context';

@Directive({
  selector: '[n-popover-trigger]',
  standalone: true,
  host: {
    'data-slot': 'trigger',
    'aria-haspopup': 'dialog',
    '[id]': 'ctx.triggerId',
    '[attr.aria-expanded]': 'ctx.open()',
    '[attr.aria-controls]': 'ctx.open() ? ctx.contentId : null',
    '[attr.data-state]': 'ctx.open() ? "open" : "closed"',
    '(click)': 'handleClick($event)',
    '(mouseenter)': 'handleMouseEnter()',
    '(mouseleave)': 'handleMouseLeave()',
    '(focus)': 'handleFocus()',
    '(blur)': 'handleBlur()',
    '(keydown)': 'handleKeydown($event)',
  },
})
export class PopoverTriggerDirective implements OnDestroy {
  protected readonly ctx = inject(POPOVER_CONTEXT);
  private readonly _host = inject<ElementRef<HTMLElement>>(ElementRef);

  constructor() {
    this.ctx.setTriggerEl(this._host.nativeElement);
  }

  ngOnDestroy(): void {
    this.ctx.setTriggerEl(null);
    this.ctx.cancelScheduledClose();
  }

  protected handleClick(event: MouseEvent): void {
    if (this.ctx.triggerMode() !== 'click') return;
    event.preventDefault();
    this.ctx.toggle();
  }

  protected handleMouseEnter(): void {
    if (this.ctx.triggerMode() !== 'hover') return;
    this.ctx.openPopover();
  }

  protected handleMouseLeave(): void {
    if (this.ctx.triggerMode() !== 'hover') return;
    this.ctx.scheduleClose(false, 150);
  }

  protected handleFocus(): void {
    if (this.ctx.triggerMode() !== 'focus') return;
    this.ctx.openPopover();
  }

  protected handleBlur(): void {
    if (this.ctx.triggerMode() !== 'focus') return;
    this.ctx.scheduleClose(false, 150);
  }

  protected handleKeydown(event: KeyboardEvent): void {
    if (this.ctx.triggerMode() !== 'click') return;
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      this.ctx.toggle();
    }
  }
}

import { FocusTrap, FocusTrapFactory } from '@angular/cdk/a11y';
import {
  ConnectedPosition,
  FlexibleConnectedPositionStrategy,
  Overlay,
  OverlayConfig,
  OverlayRef,
} from '@angular/cdk/overlay';
import { TemplatePortal } from '@angular/cdk/portal';
import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  OnDestroy,
  TemplateRef,
  ViewChild,
  ViewContainerRef,
  computed,
  effect,
  inject,
  input,
  signal,
  untracked,
} from '@angular/core';
import { Subscription } from 'rxjs';
import { mergeClasses } from '../../utils/merge-classes';
import { POPOVER_CONTEXT } from './popover.context';
import { popoverContentVariants, type PopoverContentVariants } from './popover.variants';

type Side = 'top' | 'bottom' | 'left' | 'right';
type Align = 'start' | 'center' | 'end';

@Component({
  selector: 'n-popover-content',
  standalone: true,
  template: `
    <ng-template #panel>
      <div
        #panelEl
        [id]="ctx.contentId"
        [attr.role]="ctx.modal() ? 'dialog' : 'region'"
        [attr.aria-modal]="ctx.modal() ? true : null"
        [attr.aria-labelledby]="ctx.triggerId"
        data-slot="content"
        tabindex="-1"
        [attr.data-side]="actualSide()"
        [attr.data-align]="nAlign()"
        [attr.data-state]="isClosing() ? 'closed' : 'open'"
        [class]="classes()"
        (keydown)="handleKeydown($event)"
      >
        @if (nArrow()) {
          <span [class]="arrowClass()" aria-hidden="true"></span>
        }
        <ng-content />
      </div>
    </ng-template>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents' },
})
export class PopoverContentComponent implements AfterViewInit, OnDestroy {
  readonly nSide = input<Side>('bottom');
  readonly nAlign = input<Align>('center');
  readonly nSideOffset = input<number>(8);
  readonly nAlignOffset = input<number>(0);
  readonly nArrow = input<boolean>(true);
  readonly nSize = input<PopoverContentVariants['nSize']>('default');
  readonly nClass = input<string>('');

  protected readonly ctx = inject(POPOVER_CONTEXT);
  private readonly _overlay = inject(Overlay);
  private readonly _vcr = inject(ViewContainerRef);
  private readonly _focusTrapFactory = inject(FocusTrapFactory);

  @ViewChild('panel', { static: true }) private _panelTpl!: TemplateRef<unknown>;
  @ViewChild('panelEl') private _panelEl?: ElementRef<HTMLElement>;

  private _overlayRef: OverlayRef | null = null;
  private _portal: TemplatePortal | null = null;
  private _focusTrap: FocusTrap | null = null;
  private _backdropSub?: Subscription;
  private _positionSub?: Subscription;
  private _detachTimer?: ReturnType<typeof setTimeout>;
  private _hoverDocHandler?: (e: MouseEvent) => void;

  protected readonly isClosing = signal(false);
  protected readonly actualSide = signal<Side>('bottom');

  protected readonly classes = computed(() =>
    mergeClasses(
      popoverContentVariants({ nSize: this.nSize() }),
      this.isClosing() && 'animate-out fade-out-0 zoom-out-95',
      this.nClass(),
    ),
  );

  protected readonly arrowClass = computed(() => {
    const side = this.actualSide();
    const base = 'absolute size-2.5 rotate-45 border bg-popover';
    switch (side) {
      case 'bottom':
        return `${base} -top-[5px] left-1/2 -translate-x-1/2 border-r-transparent border-b-transparent`;
      case 'top':
        return `${base} -bottom-[5px] left-1/2 -translate-x-1/2 border-t-transparent border-l-transparent`;
      case 'right':
        return `${base} -left-[5px] top-1/2 -translate-y-1/2 border-t-transparent border-r-transparent`;
      case 'left':
        return `${base} -right-[5px] top-1/2 -translate-y-1/2 border-b-transparent border-l-transparent`;
    }
  });

  constructor() {
    effect(() => {
      if (this.ctx.open()) {
        clearTimeout(this._detachTimer);
        this.isClosing.set(false);
        this._attach();
      } else if (this._overlayRef) {
        this._beginDetach();
      }
    });
  }

  ngAfterViewInit(): void {
    this._portal = new TemplatePortal(this._panelTpl, this._vcr);
  }

  ngOnDestroy(): void {
    clearTimeout(this._detachTimer);
    this._forceDetach();
  }

  private _attach(): void {
    const trigger = this.ctx.triggerEl();
    if (!trigger || !this._portal) return;
    if (this._overlayRef?.hasAttached()) return;

    const isHover = this.ctx.triggerMode() === 'hover';

    const positionStrategy = this._overlay
      .position()
      .flexibleConnectedTo(trigger)
      .withPositions(this._buildPositions())
      .withFlexibleDimensions(false)
      .withPush(true);

    const config = new OverlayConfig({
      positionStrategy,
      scrollStrategy: this._overlay.scrollStrategies.reposition(),
      hasBackdrop: !isHover,
      backdropClass: 'cdk-overlay-transparent-backdrop',
    });

    this._overlayRef = this._overlay.create(config);
    this._overlayRef.attach(this._portal);

    this._positionSub = (positionStrategy as FlexibleConnectedPositionStrategy).positionChanges.subscribe(
      (change) => {
        const pos = change.connectionPair;
        let side: Side = this.nSide();
        if (pos.originY === 'bottom' && pos.overlayY === 'top') side = 'bottom';
        else if (pos.originY === 'top' && pos.overlayY === 'bottom') side = 'top';
        else if (pos.originX === 'end' && pos.overlayX === 'start') side = 'right';
        else if (pos.originX === 'start' && pos.overlayX === 'end') side = 'left';
        this.actualSide.set(side);
      },
    );

    if (!isHover) {
      this._backdropSub = this._overlayRef.backdropClick().subscribe(() => {
        if (this.ctx.persistent()) return;
        this.ctx.close(false);
      });
    }

    queueMicrotask(() => {
      const el = this._panelEl?.nativeElement;
      if (!el) return;
      this.ctx.setPanelEl(el);

      if (isHover) {
        // Track mouse globally: keep popover open while over trigger or panel
        this._hoverDocHandler = (e: MouseEvent) => {
          const target = e.target as Node;
          const triggerEl = this.ctx.triggerEl();
          if (el.contains(target) || triggerEl?.contains(target)) {
            this.ctx.cancelScheduledClose();
          } else {
            this.ctx.scheduleClose(false, 150);
          }
        };
        document.addEventListener('mouseover', this._hoverDocHandler);
      } else if (this.ctx.modal()) {
        this._focusTrap = this._focusTrapFactory.create(el);
        this._focusTrap.focusInitialElementWhenReady();
      } else {
        el.focus();
      }
    });
  }

  private _beginDetach(): void {
    clearTimeout(this._detachTimer);
    this.isClosing.set(true);
    this.ctx.setPanelEl(null);
    this._removeHoverDocHandler();

    const triggerEl = untracked(() => this.ctx.triggerEl());
    if (triggerEl && this.ctx.modal()) triggerEl.focus({ preventScroll: true });

    this._focusTrap?.destroy();
    this._focusTrap = null;

    this._detachTimer = setTimeout(() => {
      this.isClosing.set(false);
      this._forceDetach();
    }, 150);
  }

  private _forceDetach(): void {
    this._removeHoverDocHandler();
    this._backdropSub?.unsubscribe();
    this._backdropSub = undefined;
    this._positionSub?.unsubscribe();
    this._positionSub = undefined;
    this._overlayRef?.dispose();
    this._overlayRef = null;
  }

  private _removeHoverDocHandler(): void {
    if (this._hoverDocHandler) {
      document.removeEventListener('mouseover', this._hoverDocHandler);
      this._hoverDocHandler = undefined;
    }
  }

  protected handleKeydown(event: KeyboardEvent): void {
    if (event.key !== 'Escape') return;
    event.preventDefault();
    event.stopPropagation();
    if (this.ctx.persistent()) return;
    this.ctx.close(true);
  }

  private _buildPositions(): ConnectedPosition[] {
    const side = this.nSide();
    const align = this.nAlign();
    const sideOffset = this.nSideOffset();
    const alignOffset = this.nAlignOffset();

    const buildOne = (s: Side, a: Align): ConnectedPosition => {
      const isVertical = s === 'top' || s === 'bottom';
      const originY = s === 'bottom' ? 'bottom' : s === 'top' ? 'top' : 'center';
      const overlayY = s === 'bottom' ? 'top' : s === 'top' ? 'bottom' : 'center';
      const originX = s === 'right' ? 'end' : s === 'left' ? 'start' : a === 'center' ? 'center' : a;
      const overlayX = s === 'right' ? 'start' : s === 'left' ? 'end' : a === 'center' ? 'center' : a;
      return {
        originX: originX as ConnectedPosition['originX'],
        originY: originY as ConnectedPosition['originY'],
        overlayX: overlayX as ConnectedPosition['overlayX'],
        overlayY: overlayY as ConnectedPosition['overlayY'],
        offsetX: isVertical ? alignOffset : s === 'right' ? sideOffset : -sideOffset,
        offsetY: isVertical ? (s === 'bottom' ? sideOffset : -sideOffset) : alignOffset,
      };
    };

    const opposite: Record<Side, Side> = { top: 'bottom', bottom: 'top', left: 'right', right: 'left' };
    return [buildOne(side, align), buildOne(opposite[side], align)];
  }
}

import { Directive, inject } from '@angular/core';
import { POPOVER_CONTEXT } from './popover.context';

@Directive({
  selector: '[n-popover-close]',
  standalone: true,
  host: {
    'data-slot': 'close',
    '(click)': 'ctx.close(true)',
  },
})
export class PopoverCloseDirective {
  protected readonly ctx = inject(POPOVER_CONTEXT);
}

import { InjectionToken, Signal, WritableSignal } from '@angular/core';

export interface PopoverContext {
  readonly open: WritableSignal<boolean>;
  readonly persistent: Signal<boolean>;
  readonly modal: Signal<boolean>;
  readonly triggerMode: Signal<'click' | 'hover' | 'focus'>;
  readonly triggerEl: Signal<HTMLElement | null>;
  readonly panelEl: Signal<HTMLElement | null>;
  readonly contentId: string;
  readonly triggerId: string;
  setTriggerEl(el: HTMLElement | null): void;
  setPanelEl(el: HTMLElement | null): void;
  toggle(): void;
  openPopover(): void;
  close(focusTrigger?: boolean): void;
  scheduleClose(focusTrigger?: boolean, delay?: number): void;
  cancelScheduledClose(): void;
}

export const POPOVER_CONTEXT = new InjectionToken<PopoverContext>('POPOVER_CONTEXT');

import { cva, type VariantProps } from 'class-variance-authority';

export const popoverContentVariants = cva(
  [
    'relative z-50 rounded-md border bg-popover text-popover-foreground shadow-md outline-none',
    'animate-in fade-in-0 zoom-in-95',
    'data-[side=top]:slide-in-from-bottom-2 data-[side=bottom]:slide-in-from-top-2',
    'data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2',
  ],
  {
    variants: {
      nSize: {
        sm: 'w-48 p-3 text-sm',
        default: 'w-72 p-4 text-sm',
        lg: 'w-96 p-5 text-base',
      },
    },
    defaultVariants: { nSize: 'default' },
  },
);

export type PopoverContentVariants = VariantProps<typeof popoverContentVariants>;

export * from './popover.component';
export * from './popover-trigger.directive';
export * from './popover-content.component';
export * from './popover-close.directive';
export * from './popover.context';
export * from './popover.variants';

