import { Component } from '@angular/core';
import { ButtonComponent } from '../../button/button.component';
import { PopoverCloseDirective } from '../popover-close.directive';
import { PopoverComponent } from '../popover.component';
import { PopoverContentComponent } from '../popover-content.component';
import { PopoverTriggerDirective } from '../popover-trigger.directive';

@Component({
  selector: 'demo-popover-default',
  standalone: true,
  imports: [
    PopoverComponent,
    PopoverTriggerDirective,
    PopoverContentComponent,
    PopoverCloseDirective,
    ButtonComponent,
  ],
  template: `
    <n-popover>
      <button n-button n-popover-trigger nVariant="outline">Abrir popover</button>
      <n-popover-content>
        <p class="font-medium leading-none">Dimensões</p>
        <p class="mt-1 text-muted-foreground">Define as dimensões do seu layer.</p>
        <button n-button n-popover-close nVariant="ghost" class="mt-4 w-full" nSize="sm">Fechar</button>
      </n-popover-content>
    </n-popover>
  `,
})
export class PopoverDefaultDemo {}

import { Component } from '@angular/core';
import { ButtonComponent } from '../../button/button.component';
import { PopoverComponent } from '../popover.component';
import { PopoverContentComponent } from '../popover-content.component';
import { PopoverTriggerDirective } from '../popover-trigger.directive';

@Component({
  selector: 'demo-popover-hover',
  standalone: true,
  imports: [PopoverComponent, PopoverTriggerDirective, PopoverContentComponent, ButtonComponent],
  template: `
    <n-popover nTrigger="hover">
      <button n-button n-popover-trigger nVariant="outline">Passe o mouse</button>
      <n-popover-content nSize="sm">
        <p class="font-medium leading-none">Dica rápida</p>
        <p class="mt-1 text-muted-foreground">Abre ao passar o mouse, fecha ao sair.</p>
      </n-popover-content>
    </n-popover>
  `,
})
export class PopoverHoverDemo {}

import { Component } from '@angular/core';
import { ButtonComponent } from '../../button/button.component';
import { PopoverComponent } from '../popover.component';
import { PopoverContentComponent } from '../popover-content.component';
import { PopoverTriggerDirective } from '../popover-trigger.directive';

@Component({
  selector: 'demo-popover-placement',
  standalone: true,
  imports: [PopoverComponent, PopoverTriggerDirective, PopoverContentComponent, ButtonComponent],
  template: `
    <div class="flex flex-wrap gap-2">
      @for (side of sides; track side) {
        <n-popover>
          <button n-button n-popover-trigger nVariant="outline" nSize="sm">{{ side }}</button>
          <n-popover-content [nSide]="side" nSize="sm">
            <p class="text-center font-medium">nSide="{{ side }}"</p>
          </n-popover-content>
        </n-popover>
      }
    </div>
  `,
})
export class PopoverPlacementDemo {
  readonly sides = ['top', 'bottom', 'left', 'right'] as const;
}

import { Component, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ButtonComponent } from '../../button/button.component';
import { InputComponent } from '../../input/input.component';
import { PopoverCloseDirective } from '../popover-close.directive';
import { PopoverComponent } from '../popover.component';
import { PopoverContentComponent } from '../popover-content.component';
import { PopoverTriggerDirective } from '../popover-trigger.directive';

@Component({
  selector: 'demo-popover-with-form',
  standalone: true,
  imports: [
    FormsModule,
    PopoverComponent,
    PopoverTriggerDirective,
    PopoverContentComponent,
    PopoverCloseDirective,
    ButtonComponent,
    InputComponent,
  ],
  template: `
    <n-popover [nModal]="true" [nPersistent]="true">
      <button n-button n-popover-trigger nVariant="outline">Editar perfil</button>
      <n-popover-content nSize="lg">
        <p class="font-medium leading-none">Editar perfil</p>
        <p class="mt-1 text-muted-foreground text-xs">Faça alterações no seu perfil aqui.</p>
        <div class="mt-4 grid gap-3">
          <n-input nLabel="Nome" [(nValue)]="name" />
          <n-input nLabel="Usuário" [(nValue)]="username" />
        </div>
        <div class="mt-4 flex justify-end gap-2">
          <button n-button n-popover-close nVariant="outline" nSize="sm">Cancelar</button>
          <button n-button n-popover-close nSize="sm" (click)="save()">Salvar</button>
        </div>
      </n-popover-content>
    </n-popover>
  `,
})
export class PopoverWithFormDemo {
  name = signal('João Silva');
  username = signal('@joaosilva');

  save(): void {
    console.log('Salvo', this.name(), this.username());
  }
}
